import 'dart:math';

void main() {
  final random = Random();

  final maxExclusive = 101;
  final randomIntUpto = random.nextInt(maxExclusive);
  print('Random Integer [0-${maxExclusive - 1}]: ${randomIntUpto}');

  final minVal = 10;
  final maxVal = 20;
  final randomInRange = minVal + random.nextInt(maxVal - minVal + 1);
  print('Random Integer [${minVal}-${maxVal}]: ${randomInRange}');

  final randomDouble = random.nextDouble();
  print('Random Double [0.0, 1.0): ${randomDouble}');

  final randomBool = random.nextBool();
  print('Random Boolean: ${randomBool}');

  final fruits = ['apple', 'banana', 'cherry'];
  if (fruits.isNotEmpty) {
    final randomFruit = fruits[random.nextInt(fruits.length)];
    print('Random fruit: ${randomFruit}');
  }
}

