// Helper function using runes for Unicode correctness
String reverseString(String input) {
  return String.fromCharCodes(input.runes.toList().reversed);
}

void main() {
  final originalString = "Dart Programming";
  print('Original: ${originalString}');

  final reversedStr = reverseString(originalString);
  print('Reversed: ${reversedStr}');

  final originalUnicode = "你好 Dart";
  final reversedUnicode = reverseString(originalUnicode);
  print('Original Unicode: ${originalUnicode}');
  print('Reversed Unicode: ${reversedUnicode}');
}

