import 'dart:math';

BigInt fibonacci(int n) {
  if (n < 0) throw ArgumentError("Input must be non-negative");
  if (n == 0) return BigInt.zero;
  if (n == 1) return BigInt.one;

  var a = BigInt.zero;
  var b = BigInt.one;

  for (int i = 2; i <= n; i++) {
    final next = a + b;
    a = b;
    b = next;
  }
  return b;
}

List<BigInt> generateFibonacciSequence(int count) {
   if (count < 0) throw ArgumentError("Count must be non-negative");
   return List.generate(count, (index) => fibonacci(index), growable: false);
}

void main() {
  final n = 10;
  print('Fibonacci number F(${n}): ${fibonacci(n)}');

  final numTerms = 15;
  print('First ${numTerms} Fibonacci numbers:');
  final sequenceList = generateFibonacciSequence(numTerms);
  print(sequenceList);

  final largeN = 90;
  print('Fibonacci number F(${largeN}): ${fibonacci(largeN)}');
}

factorial:
import 'dart:math';

BigInt factorial(int n) {
  if (n < 0) throw ArgumentError("Factorial input must be non-negative");
  var result = BigInt.one;
  if (n == 0) return result;
  for (int i = 2; i <= n; i++) {
    result *= BigInt.from(i);
  }
  return result;
}

void main() {
  final num = 5;
  print('Factorial of ${num} is: ${factorial(num)}');

  final numZero = 0;
  print('Factorial of ${numZero} is: ${factorial(numZero)}');

  final numLarge = 30;
  print('Factorial of ${numLarge} is: ${factorial(numLarge)}');

  try {
    factorial(-3);
  } catch (e) {
    print('Error calculating factorial: ${e}');
  }
}

