import 'dart:math';

bool isPrime(int n) {
  if (n <= 1) return false;
  if (n <= 3) return true;
  if (n % 2 == 0 || n % 3 == 0) return false;

  final limit = sqrt(n).toInt();
  for (int i = 5; i <= limit; i += 6) {
    if (n % i == 0 || n % (i + 2) == 0) {
      return false;
    }
  }
  return true;
}

void main() {
  final numbersToCheck = <int>[2, 3, 4, 17, 25, 29, 97, 100, 1, -5, 1000000007];
  for (final n in numbersToCheck) {
    if (isPrime(n)) {
      print('${n} is prime.');
    } else {
      print('${n} is not prime.');
    }
  }
}

