import 'dart:io';
import 'dart:convert';

Future<void> main() async {
  final filePath = 'dart_read_test.txt';
  final fileWrite = File(filePath);
  final dummyContent = 'Line 1 content from Dart.\nThis is the second line.\nEnd.';

  try {
    await fileWrite.writeAsString(dummyContent, encoding: utf8);
    print('Created dummy file "${filePath}" for reading.');
  } catch (e) {
    print('Error creating dummy file: ${e}');
    return;
  }

  print('\n--- Reading file "${filePath}" ---');
  final fileRead = File(filePath);

  if (await fileRead.exists()) {
    try {
      print('\n--- Reading using file.readAsString() ---');
      final content = await fileRead.readAsString();
      print('File content as single string:');
      print(content);
      print('--- End of readAsString ---');

      print('\n--- Reading using file.readAsLines() ---');
      final lines = await fileRead.readAsLines();
      print('Read ${lines.length} lines:');
      lines.asMap().forEach((index, line) {
        print('Line ${index + 1}: ${line}');
      });
      print('--- End of readAsLines ---');

    } catch (e) {
      print('An error occurred while reading the file: ${e}');
    } finally {
      await fileRead.delete();
      print('\nCleaned up dummy file "${filePath}".');
    }
  } else {
    print('Error: File not found: "${filePath}"');
  }
}

writeFile:
import 'dart:io';
import 'dart:convert';

Future<void> main() async {
  final filePath = 'output_dart.txt';
  final initialLines = [
    'First line written by Dart.',
    'Second line using writeAsString.'
  ];
  final lineToAppend = 'Third line, appended using APPEND mode.';

  print('--- Writing to "${filePath}" (overwrite) ---');
  final fileWrite = File(filePath);
  try {
    final initialContent = initialLines.join(Platform.lineTerminator) + Platform.lineTerminator;
    await fileWrite.writeAsString(initialContent, mode: FileMode.write, encoding: utf8);
    print('Successfully wrote initial content.');
  } catch (e) {
    print('Error writing to "${filePath}": ${e}');
  }

  print('\n--- Appending to "${filePath}" ---');
  try {
    await fileWrite.writeAsString(lineToAppend + Platform.lineTerminator, mode: FileMode.append, encoding: utf8);
    print('Successfully appended content.');
  } catch (e) {
    print('Error appending to "${filePath}": ${e}');
  }

  print('\n--- Final content of "${filePath}": ---');
  final readFile = File(filePath);
  if (await readFile.exists()) {
    try {
      print(await readFile.readAsString());
    } catch (e) {
      print('Error reading back file: ${e}');
    }
  } else {
    print('File "${filePath}" not found for display.');
  }
}

