import 'dart:io';

Future<void> main() async {
  final fileToCheck = 'dart_exists_test.dart';
  final dirToCheck = 'MyDartFolder';
  final nonExistent = 'NoSuchThingHereDart.xyz';

  final fileObj = File(fileToCheck);
  final dirObj = Directory(dirToCheck);

  try {
    await fileObj.create();
    await dirObj.create(recursive: true);
    print('Created/Ensured dummy file "${fileToCheck}" and directory "${dirToCheck}"');
  } catch (e) {
    print('Error creating dummies: ${e}');
    return;
  }

  print('\n--- Checking Existence and Type ---');

  final fileType = await FileSystemEntity.type(fileToCheck);
  final dirType = await FileSystemEntity.type(dirToCheck);
  final nonExistentType = await FileSystemEntity.type(nonExistent);

  print('Type of "${fileToCheck}": ${fileType}');
  print('Type of "${dirToCheck}": ${dirType}');
  print('Type of "${nonExistent}": ${nonExistentType}');

  print('\n"${fileToCheck}" is file? ${await FileSystemEntity.isFile(fileToCheck)}');
  print('"${dirToCheck}" is directory? ${await FileSystemEntity.isDirectory(dirToCheck)}');
  print('"${nonExistent}" exists? ${await FileSystemEntity.type(nonExistent) != FileSystemEntityType.notFound}');

  print('\nCleaning up...');
  try {
     await fileObj.delete();
     await dirObj.delete();
     print('Cleaned up dummy file and directory.');
  } catch (e) {
     print('Error during cleanup: ${e}');
  }
}

