import 'package:intl/intl.dart';

void main() {
  print('--- Current Date and Time ---');
  final now = DateTime.now();
  final utcNow = DateTime.now().toUtc();

  print('Current DateTime (local): ${now}');
  print('Current DateTime (UTC): ${utcNow}');
  print('Local TimeZone Name: ${now.timeZoneName}');
  print('Local TimeZone Offset: ${now.timeZoneOffset}');

  print('\n--- Common Formats ---');
  print('ISO 8601: ${now.toIso8601String()}');
  print('Short Date (intl): ${DateFormat.yMd().format(now)}');
  print('Short Time (intl): ${DateFormat.jms().format(now)}');

  print('\n--- Custom Formatting (using intl) ---');
  try {
      final formatter1 = DateFormat('yyyy-MM-dd HH:mm:ss');
      print('Custom (yyyy-MM-dd HH:mm:ss): ${formatter1.format(now)}');
      final formatter2 = DateFormat("EEEE, MMMM dd, yyyy 'at' hh:mm:ss a zzzz");
      print('Readable: ${formatter2.format(now)}');
  } catch (e) {
      print ('Formatting failed, ensure intl package is initialized if needed.');
      print ('Manual format: ${now.year}-${now.month.toString().padLeft(2,"0")}-${now.day.toString().padLeft(2,"0")}');
  }

  print('\n--- Components ---');
  print('Year: ${now.year}');
  print('Month: ${now.month}');
  print('Day: ${now.day}');
  print('Hour: ${now.hour}');
  print('Minute: ${now.minute}');
  print('Second: ${now.second}');
  print('Weekday: ${now.weekday} (1=Mon, 7=Sun)');

  print('\n--- Unix Epoch Time ---');
  final epochMillis = now.millisecondsSinceEpoch;
  print('Milliseconds since epoch (UTC): ${epochMillis}');
  final epochSeconds = (epochMillis / 1000).floor();
  print('Seconds since epoch (UTC): ${epochSeconds}');
}

